  'mc.title':         { en: '⚖️ Meal Footprint Comparison', fr: '⚖️ Comparateur d\u2019empreinte des repas', 'zh-CN': '⚖️ 餐盘足迹对比',                'zh-TW': '⚖️ 餐盤足跡對比' },
  'mc.sub':           { en: 'Build two plates and see their carbon & water footprints side-by-side. Swap one ingredient and watch the difference — choices on the plate are some of the most powerful climate levers an individual has.',
                        fr: 'Composez deux assiettes et comparez leur empreinte carbone et eau. Changez un ingrédient et observez la différence — l\u2019assiette est l\u2019un des leviers climatiques individuels les plus puissants.',
                        'zh-CN': '搭配两份餐盘并对比它们的碳与水足迹。换掉一种食材就能看出差距——餐盘上的选择是个人最有力的气候杠杆之一。',
                        'zh-TW': '搭配兩份餐盤並比較它們的碳與水足跡。換掉一種食材就能看出差距——餐盤上的選擇是個人最有力的氣候槓桿之一。' },
  'mc.presetsLabel':  { en: 'Try a preset:',                fr: 'Essayez un modèle :',                      'zh-CN': '试试预设搭配:',                 'zh-TW': '試試預設搭配：' },
  'mc.preset.burger':    { en: '🍔 Beef vs Lentil Burger',     fr: '🍔 Burger bœuf vs lentilles',           'zh-CN': '🍔 牛肉 vs 扁豆汉堡',           'zh-TW': '🍔 牛肉 vs 扁豆漢堡' },
  'mc.preset.steakbowl': { en: '🥩 Steak Dinner vs Vegan Bowl',fr: '🥩 Steak vs bol végétal',               'zh-CN': '🥩 牛排餐 vs 全素碗',           'zh-TW': '🥩 牛排餐 vs 全素碗' },
  'mc.preset.pizza':     { en: '🍕 Pepperoni vs Margherita',   fr: '🍕 Pepperoni vs Margherita',            'zh-CN': '🍕 意式辣肠 vs 玛格丽特',       'zh-TW': '🍕 義式辣腸 vs 瑪格麗特' },
  'mc.preset.taco':      { en: '🌮 Beef vs Veggie Tacos',      fr: '🌮 Tacos bœuf vs légumes',              'zh-CN': '🌮 牛肉 vs 蔬菜塔可',           'zh-TW': '🌮 牛肉 vs 蔬菜塔可' },
  'mc.preset.milk':      { en: '🥛 Dairy vs Oat Milk Latte',   fr: '🥛 Latte lait vs avoine',               'zh-CN': '🥛 牛奶 vs 燕麦奶拿铁',         'zh-TW': '🥛 牛奶 vs 燕麥奶拿鐵' },
  'mc.add':           { en: '+ Add',                        fr: '+ Ajouter',                                'zh-CN': '+ 添加',                        'zh-TW': '+ 加入' },
  'mc.chartTitle':    { en: '📊 Side-by-side footprint',    fr: '📊 Empreinte côte à côte',                 'zh-CN': '📊 并排足迹对比',               'zh-TW': '📊 並排足跡對比' },
  'mc.disclaimer':    { en: '💡 Footprints are typical per-serving averages from Poore & Nemecek (Science, 2018) and Mekonnen & Hoekstra (Water Footprint Network). Real values vary with farming method, transport and waste — these figures show the order of magnitude.',
                        fr: '💡 Les empreintes sont des moyennes typiques par portion (Poore & Nemecek, Science 2018 ; Mekonnen & Hoekstra, Water Footprint Network). Les valeurs réelles varient selon le mode de production, le transport et le gaspillage — ces chiffres donnent l\u2019ordre de grandeur.',
                        'zh-CN': '💡 数据为每份的典型平均值,来自 Poore & Nemecek(Science 2018)与 Mekonnen & Hoekstra(水足迹网络)。实际数值会因种植方式、运输与浪费而异——这些数字仅反映数量级。',
                        'zh-TW': '💡 數據為每份的典型平均值，來自 Poore & Nemecek（Science 2018）與 Mekonnen & Hoekstra（水足跡網絡）。實際數值會因種植方式、運輸與浪費而異——這些數字僅反映數量級。' },
  'mc.empty':         { en: 'Add some items to this plate to see its footprint.', fr: 'Ajoutez des éléments à cette assiette pour voir son empreinte.', 'zh-CN': '请向此餐盘添加食物以查看足迹。', 'zh-TW': '請向此餐盤加入食物以查看足跡。' },
