  'vamp.ledHours':      { en: 'hours of LED bulb',             fr: 'heures d\u2019ampoule LED',                'zh-CN': '小时 LED 灯泡',               'zh-TW': '小時 LED 燈泡' },
  'vamp.trees':         { en: 'trees needed to offset (per year)', fr: 'arbres pour compenser (par an)',        'zh-CN': '棵树才能抵消 (每年)',         'zh-TW': '棵樹才能抵消 (每年)' },
  'vamp.kmCar':         { en: 'km driven in a petrol car',     fr: 'km en voiture essence',                    'zh-CN': '公里燃油车里程',              'zh-TW': '公里燃油車里程' },
  'vamp.breakdownTitle':{ en: 'Worst offenders',               fr: 'Pires coupables',                          'zh-CN': '最大耗电源头',                'zh-TW': '最大耗電來源' },
  'vamp.tip':           { en: '💡 Quick wins: plug audio/video gear into a switched power strip; unplug chargers when not charging; enable “eco / instant-off” mode on game consoles and set-top boxes. A simple smart plug pays for itself in months.',
                          fr: '💡 Gains rapides : branchez l\u2019audio/vidéo sur une multiprise avec interrupteur ; débranchez les chargeurs inutilisés ; activez le mode « éco / arrêt rapide » sur les consoles et décodeurs. Une simple prise connectée est rentabilisée en quelques mois.',
                          'zh-CN': '💡 速效之举:把音视频设备插到带开关的排插上;不充电时拔掉充电器;在游戏主机和机顶盒上开启"节能 / 即时关机"模式。一个智能插座几个月就能回本。',
                          'zh-TW': '💡 速效之舉：把音視訊設備插到帶開關的排插上；不充電時拔掉充電器；在遊戲主機和機上盒上開啟「節能 / 即時關機」模式。一個智慧插座幾個月就能回本。' },
  'vamp.disclaimer':    { en: '💡 Standby wattages are typical averages compiled from Lawrence Berkeley National Lab, IEA 4E and EU Ecodesign reports. Modern devices on the latest standards draw less; older equipment can draw far more. Adjust electricity price and grid intensity for your country to refine the result.',
                          fr: '💡 Les puissances en veille sont des moyennes typiques compilées à partir des rapports du Lawrence Berkeley National Lab, de l\u2019AIE 4E et de l\u2019Écoconception de l\u2019UE. Les appareils récents conformes aux dernières normes en consomment moins ; les anciens beaucoup plus. Ajustez prix de l\u2019électricité et intensité du réseau pour affiner.',
                          'zh-CN': '💡 待机功率为来自劳伦斯伯克利国家实验室、IEA 4E 与欧盟 Ecodesign 报告的典型平均值。符合最新标准的新设备能耗更低,老设备则可能高得多。请根据所在国调整电价和电网强度以获得更精确的结果。',
                          'zh-TW': '💡 待機功率為來自勞倫斯伯克利國家實驗室、IEA 4E 與歐盟 Ecodesign 報告的典型平均值。符合最新標準的新設備能耗更低，老設備則可能高得多。請依所在國調整電價和電網強度以取得更精確的結果。' },

  'laundry.title':       { en: '🧺 Eco-Laundry Scheduler',    fr: '🧺 Planificateur de lessive éco',  'zh-CN': '🧺 环保洗衣调度器',           'zh-TW': '🧺 環保洗衣排程器' },
  'laundry.sub':         { en: 'A tumble dryer burns ~3 kWh per load. Wash when conditions favour line-drying and you skip nearly all of that. This tool reads live weather and finds the best wash & line-dry windows for your location.',
                           fr: 'Un sèche-linge consomme ~3 kWh par cycle. Lavez quand la météo permet l\u2019étendage et vous évitez presque tout. Cet outil lit la météo en direct et trouve les meilleurs créneaux pour laver et sécher à l\u2019air libre.',
                           'zh-CN': '一次烘干机循环要耗约 3 kWh。挑选天气适合晾晒的时间洗衣,就能省下几乎所有这些电。本工具读取实时天气,为你的城市找出最佳洗衣与晾晒时段。',
                           'zh-TW': '一次烘衣機循環要耗約 3 kWh。挑選天氣適合晾曬的時間洗衣，就能省下幾乎所有這些電。本工具讀取即時天氣，為你的城市找出最佳洗衣與晾曬時段。' },
