  'laundry.level.good':      { en: 'Good — line-dry should work',         fr: 'Bon — l\u2019étendage devrait marcher',    'zh-CN': '良好 — 可以晾晒',             'zh-TW': '良好 — 可以晾曬' },
  'laundry.level.ok':        { en: 'OK — drying will be slow',            fr: 'Correct — séchage lent',                   'zh-CN': '一般 — 干得较慢',             'zh-TW': '一般 — 乾得較慢' },
