  'laundry.level.bad':       { en: 'Bad — dryer or wait',                 fr: 'Mauvais — sèche-linge ou attendez',        'zh-CN': '不适合 — 用烘干机或等等',     'zh-TW': '不適合 — 用烘衣機或等等' },
  'laundry.tip.cold':         { en: 'Wash at 30 °C (cold) — saves ~60 % of cycle energy vs hot wash.', fr: 'Lavez à 30 °C (froid) — économise ~60 % de l\u2019énergie d\u2019un cycle chaud.', 'zh-CN': '使用 30°C 冷水洗 — 比热水洗节能约 60%。', 'zh-TW': '使用 30°C 冷水洗 — 比熱水洗節能約 60%。' },
  'laundry.tip.full':         { en: 'Run full loads — half loads use ~80 % of the water and energy of a full one.', fr: 'Lancez des cycles pleins — un demi-cycle utilise ~80 % de l\u2019eau et de l\u2019énergie d\u2019un cycle plein.', 'zh-CN': '装满了再洗 — 半桶洗衣会消耗整桶约 80% 的水与电。', 'zh-TW': '裝滿了再洗 — 半桶洗衣會消耗整桶約 80% 的水與電。' },
  'laundry.tip.lineDry':      { en: 'Line-dry during the green windows below to skip ~3 kWh of dryer energy per load.', fr: 'Étendez pendant les créneaux verts ci-dessous pour économiser ~3 kWh de sèche-linge par cycle.', 'zh-CN': '在下方"绿色时段"晾晒,每次可省下烘干机约 3 kWh 用电。', 'zh-TW': '在下方「綠色時段」晾曬，每次可省下烘衣機約 3 kWh 用電。' },
  'laundry.tip.rack':         { en: 'Use an indoor drying rack near a vent or warm room; running a small fan beats a tumble dryer.', fr: 'Utilisez un étendoir intérieur près d\u2019une bouche d\u2019aération ; un petit ventilateur consomme bien moins qu\u2019un sèche-linge.', 'zh-CN': '把室内晾衣架放在通风或较暖的房间;开个小风扇也比烘干机省得多。', 'zh-TW': '把室內晾衣架放在通風或較暖的房間；開個小風扇也比烘衣機省得多。' },
  'laundry.tip.highHum':      { en: 'Humidity is high right now — clothes may take longer to dry; open windows or use a dehumidifier.', fr: 'L\u2019humidité est élevée — le séchage sera plus lent ; aérez ou utilisez un déshumidificateur.', 'zh-CN': '当前湿度偏高,衣物干得慢——开窗通风或用除湿机。', 'zh-TW': '目前濕度偏高，衣物乾得慢——開窗通風或用除濕機。' },
  'laundry.tip.wind':         { en: 'Breezy day — clip the heaviest items at the corners so they don\u2019t fly off.', fr: 'Journée venteuse — fixez bien les pièces lourdes aux pinces d\u2019angle.', 'zh-CN': '今天风大,把重衣物的四角夹紧,免得被吹走。', 'zh-TW': '今天風大，把重衣物的四角夾緊，免得被吹走。' },
  'laundry.tip.cold_weather': { en: 'Cold outside — line-drying still works but takes longer; an unheated indoor rack works almost as well.', fr: 'Il fait froid dehors — l\u2019étendage marche encore mais prend plus de temps ; un étendoir intérieur non chauffé est presque aussi efficace.', 'zh-CN': '室外较冷,晾在外面也能干但要更久;不加热的室内晾衣架几乎一样有效。', 'zh-TW': '室外較冷，晾在外面也能乾但要更久；不加熱的室內晾衣架幾乎一樣有效。' },
  'laundry.disclaimer':  { en: '💡 Forecast data from Open-Meteo (free, no API key, ECMWF + national weather services). Drying-friendliness score combines temperature, humidity, wind, cloud cover and precipitation probability — higher is better. A typical electric tumble dryer uses 2–4 kWh per load; line-drying when conditions allow eliminates almost all of that emission.',
                           fr: '💡 Données météo Open-Meteo (gratuit, sans clé API, ECMWF + services nationaux). L\u2019indice de séchage combine température, humidité, vent, nébulosité et probabilité de pluie — plus c\u2019est élevé, mieux c\u2019est. Un sèche-linge électrique consomme 2–4 kWh par cycle ; l\u2019étendage quand les conditions le permettent élimine presque toute cette émission.',
                           'zh-CN': '💡 天气数据来自 Open-Meteo(免费、无需 API 密钥,源自 ECMWF 与各国气象服务)。"晾干指数"综合气温、湿度、风速、云量与降水概率——分越高越好。一台电烘干机一次循环耗 2–4 kWh;在条件允许时晾晒可省下几乎全部排放。',
                           'zh-TW': '💡 天氣資料來自 Open-Meteo（免費、無需 API 金鑰，源自 ECMWF 與各國氣象服務）。「晾乾指數」綜合氣溫、濕度、風速、雲量與降水機率——分數越高越好。一台電烘衣機一次循環耗 2–4 kWh；在條件允許時晾曬可省下幾乎全部排放。' },

  'trk.title':            { en: '📈 Personal Footprint Tracker',  fr: '📈 Suivi personnel d\u2019empreinte',   'zh-CN': '📈 个人足迹追踪器',           'zh-TW': '📈 個人足跡追蹤器' },
  'trk.sub':              { en: 'Log your daily activities and watch your carbon footprint over time. Hit the Paris-aligned target of 2.5 kg CO₂ / day to earn badges and march toward Net Zero.',
                            fr: 'Enregistrez vos activités quotidiennes et suivez votre empreinte carbone dans le temps. Atteignez la cible Paris-compatible de 2,5 kg CO₂ / jour pour gagner des badges et viser le Net Zéro.',
                            'zh-CN': '记录日常活动,跟踪你的碳足迹趋势。达到 2.5 kg CO₂/日 的巴黎协定个人目标,即可解锁徽章,迈向净零。',
                            'zh-TW': '記錄日常活動，追蹤你的碳足跡趨勢。達到 2.5 kg CO₂/日 的巴黎協定個人目標，即可解鎖徽章，邁向淨零。' },
