  'trk.earlyDays':        { en: 'Early days — every entry helps.',     fr: 'Tout début — chaque entrée compte.',    'zh-CN': '才刚开始——每条记录都有帮助。',          'zh-TW': '才剛開始——每條記錄都有幫助。' },
