// ── State + Core API ─────────────────────────────────────────────
let currentLang = (typeof localStorage !== 'undefined' && localStorage.getItem('ecotrack-lang')) || 'en';
if (!LANGUAGES.some(l => l.code === currentLang)) currentLang = 'en';

function t(key) {
  const entry = T[key];
  if (!entry) return key;
  return entry[currentLang] || entry.en || key;
}

function tField(obj) {
  if (!obj) return '';
  if (typeof obj === 'string') return obj;
  return obj[currentLang] || obj.en || '';
}

function applyI18n(root) {
  const scope = root || document;
  // text content
  scope.querySelectorAll('[data-i18n]').forEach(el => {
    el.textContent = t(el.dataset.i18n);
  });
  // placeholders
  scope.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
    el.placeholder = t(el.dataset.i18nPlaceholder);
  });
  // <title>
  if (scope === document) {
    const titleKey = document.documentElement.dataset.i18nTitle;
    if (titleKey) document.title = t(titleKey);
    document.documentElement.lang = currentLang;
  }
}

function setLang(code) {
  if (!LANGUAGES.some(l => l.code === code)) return;
  currentLang = code;
  try { localStorage.setItem('ecotrack-lang', code); } catch (e) {}
  applyI18n();
  document.querySelectorAll('[data-lang-btn]').forEach(b => {
    b.classList.toggle('active', b.dataset.langBtn === code);
  });
  document.dispatchEvent(new CustomEvent('ecotrack:langchange', { detail: { lang: code } }));
}

function getLang() { return currentLang; }

// Build the language selector and wire it up
function initLangSelector() {
  const host = document.getElementById('lang-selector');
  if (!host) return;
  host.innerHTML = LANGUAGES.map(l =>
    `<button class="lang-btn${l.code === currentLang ? ' active' : ''}" data-lang-btn="${l.code}" title="${l.label}" aria-label="${l.label}">${l.short}</button>`
  ).join('');
  host.querySelectorAll('[data-lang-btn]').forEach(b => {
    b.addEventListener('click', () => setLang(b.dataset.langBtn));
  });
}

document.addEventListener('DOMContentLoaded', () => {
  initLangSelector();
  applyI18n();
});

// Expose to app.js
window.i18n = {
  t, tField, getLang, setLang,
  SEA_LEVEL_T, STORIES_T,
  QUIZ_T, SORTER_T, LIFECYCLES_T, THRIFT_T,
  ENERGY_SOURCES_T, ENERGY_LEVELS_T,
  QUEST_T, RANKS_T, CORP_T, POLICIES_T, ASSOCIATIONS_T,
};
